import os
from flask import Flask, request, jsonify
from kafka import KafkaProducer

KAFKA_BOOTSTRAP_SERVERS = os.getenv("KAFKA_BOOTSTRAP_SERVERS", "localhost:9092").split(",")
KAFKA_CLIENT_ID = os.getenv("KAFKA_CLIENT_ID", "flexible-event-publisher")
DEFAULT_TOPIC = os.getenv("DEFAULT_TOPIC", "events")

producer = KafkaProducer(
    bootstrap_servers=KAFKA_BOOTSTRAP_SERVERS,
    client_id=KAFKA_CLIENT_ID,
    value_serializer=lambda v: v if isinstance(v, (bytes, bytearray)) else str(v).encode("utf-8"),
    key_serializer=lambda v: v if v is None or isinstance(v, (bytes, bytearray)) else str(v).encode("utf-8"),
    acks=os.getenv("KAFKA_ACKS", "1"),
    linger_ms=int(os.getenv("KAFKA_LINGER_MS", "0")),
    retries=int(os.getenv("KAFKA_RETRIES", "3")),
)

app = Flask(__name__)

@app.route("/publish", methods=["POST", "GET"])
def publish():
    topic = request.args.get("topic") or request.form.get("topic") or DEFAULT_TOPIC
    key = request.args.get("key") or request.form.get("key")
    payload = request.get_data(cache=False)
    if not payload:
        payload = (request.args.get("message") or request.form.get("message") or "").encode("utf-8")

    headers = []
    for k, v in request.headers.items():
        if k.lower().startswith("x-kafka-header-"):
            headers.append((k[len("x-kafka-header-"):].encode("utf-8"), v.encode("utf-8")))

    try:
        future = producer.send(topic, value=payload, key=key, headers=headers if headers else None)
        record = future.get(timeout=float(os.getenv("KAFKA_SEND_TIMEOUT", "10")))
        return jsonify(
            ok=True,
            topic=record.topic,
            partition=record.partition,
            offset=record.offset,
            timestamp=getattr(record, "timestamp", None),
        ), 200
    except Exception as e:
        return jsonify(ok=False, error=str(e)), 500

@app.route("/healthz", methods=["GET"])
def healthz():
    return "ok", 200

if __name__ == "__main__":
    host = os.getenv("HOST", "0.0.0.0")
    port = int(os.getenv("PORT", "8080"))
    app.run(host=host, port=port)